import math

def stirling_second_kind(n, k):
    if n == 0 or k == 0 or k > n:
        return 0
    if k == 1 or k == n:
        return 1

    return k * stirling_second_kind(n - 1, k) + stirling_second_kind(n - 1, k - 1)

def count_partitions(n, k):
    if k == 0:
        return 0
    if n < 2 * k:
        return 0
    if n == 2 * k:
        return math.factorial(n) // (math.factorial(2) ** k * math.factorial(k))

    total = 0
    for i in range(k, n // 2 + 1):
        total += stirling_second_kind(n, i) * math.comb(i, k) * math.factorial(k)

    return total

# Test cases
print(count_partitions(4, 1))  # Output: 1
print(count_partitions(6, 1))  # Output: 1
print(count_partitions(5, 1))  # Output: 0


