def find_peak(grid):
    rows = len(grid)
    if rows == 0:
        return None
    cols = len(grid[0])

    for i in range(rows):
        for j in range(cols):
            current = grid[i][j]
            is_peak = True

            # Check all four directions
            for di, dj in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                ni, nj = i + di, j + dj
                if 0 <= ni < rows and 0 <= nj < cols:
                    if grid[ni][nj] > current:
                        is_peak = False
                        break

            if is_peak:
                return (i, j)

    return None


