def find_peak(grid):
    rows = len(grid)
    if rows == 0:
        return None
    cols = len(grid[0])

    left, right = 0, cols - 1

    while left <= right:
        mid_col = (left + right) // 2
        max_row = 0
        for i in range(rows):
            if grid[i][mid_col] > grid[max_row][mid_col]:
                max_row = i

        left_is_bigger = mid_col > 0 and grid[max_row][mid_col - 1] > grid[max_row][mid_col]
        right_is_bigger = mid_col < cols - 1 and grid[max_row][mid_col + 1] > grid[max_row][mid_col]

        if not left_is_bigger and not right_is_bigger:
            return (max_row, mid_col)
        elif left_is_bigger:
            right = mid_col - 1
        else:
            left = mid_col + 1

    return None


