def find_peak(grid):
    rows = len(grid)
    if rows == 0:
        return None
    cols = len(grid[0])

    def is_peak(i, j):
        current = grid[i][j]
        for di, dj in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            ni, nj = i + di, j + dj
            if 0 <= ni < rows and 0 <= nj < cols:
                if grid[ni][nj] > current:
                    return False
        return True

    for i in range(rows):
        for j in range(cols):
            if is_peak(i, j):
                return (i, j)

    return None


