def find_peak(grid):
    rows = len(grid)
    if rows == 0:
        return None
    cols = len(grid[0])

    for i in range(rows):
        for j in range(cols):
            current = grid[i][j]
            is_peak = True

            # Check all four possible neighbors
            neighbors = []
            if i > 0:
                neighbors.append(grid[i-1][j])
            if i < rows - 1:
                neighbors.append(grid[i+1][j])
            if j > 0:
                neighbors.append(grid[i][j-1])
            if j < cols - 1:
                neighbors.append(grid[i][j+1])

            for neighbor in neighbors:
                if neighbor > current:
                    is_peak = False
                    break

            if is_peak:
                return (i, j)

    return None


