        return None

    rows = len(grid)
    cols = len(grid[0])

    for i in range(rows):
        for j in range(cols):
            current = grid[i][j]
            is_peak = True

            # Check the four adjacent cells
            if i > 0 and grid[i-1][j] > current:
                is_peak = False
            if i < rows - 1 and grid[i+1][j] > current:
                is_peak = False
            if j > 0 and grid[i][j-1] > current:
                is_peak = False
            if j < cols - 1 and grid[i][j+1] > current:
                is_peak = False

            if is_peak:
                return (i, j)

    return None


