import itertools
import math

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            return False
    return True

def get_primes_up_to(n):
    primes = []
    for i in range(2, n + 1):
        if is_prime(i):
            primes.append(i)
    return primes

def replace_digits(n, digits, replacement):
    s = str(n)
    new_s = []
    for i, c in enumerate(s):
        if i in digits:
            new_s.append(str(replacement))
        else:
            new_s.append(c)
    return int(''.join(new_s))

def find_smallest_prime_family(size, num_digits):
    primes = get_primes_up_to(10**num_digits - 1)
    for num_replaced in range(1, num_digits + 1):
        for digits in itertools.combinations(range(num_digits), num_replaced):
            for replacement in range(10):
                family = []
                for prime in primes:
                    if len(str(prime)) == num_digits:
                        new_num = replace_digits(prime, digits, replacement)
                        if is_prime(new_num):
                            family.append(new_num)
                if len(family) >= size:
                    return min(family)
    return None

# We are looking for the smallest prime which, by replacing part of the number
# (not necessarily adjacent digits) with the same digit, is part of an eight prime value family.
print(find_smallest_prime_family(8, 6))


