import math

def sum_proper_divisors(n):
    if n == 1:
        return 0
    total = 1
    sqrt_n = int(math.sqrt(n))
    for i in range(2, sqrt_n + 1):
        if n % i == 0:
            total += i
            other = n // i
            if other != i:
                total += other
    return total

def find_amicable_numbers(limit):
    amicable_numbers = set()
    for a in range(2, limit):
        b = sum_proper_divisors(a)
        if b != a and sum_proper_divisors(b) == a:
            amicable_numbers.add(a)
            amicable_numbers.add(b)
    return amicable_numbers

amicable_numbers = find_amicable_numbers(10000)
print(sum(amicable_numbers))


+++++ cot_reasoning/22_names_scores/names_scores.py
def calculate_name_score(name, position):
    alphabetical_value = sum(ord(char) - ord('A') + 1 for char in name)
    return alphabetical_value * position

def total_names_scores(file_path):
    with open(file_path, 'r') as file:
        names = file.read().replace('"', '').split(',')
    names.sort()
    total_score = sum(calculate_name_score(name, i + 1) for i, name in enumerate(names))
    return total_score

file_path = 'names.txt'
print(total_names_scores(file_path))


