import math

def sum_proper_divisors(n):
    if n == 1:
        return 0
    total = 1
    sqrt_n = int(math.sqrt(n))
    for i in range(2, sqrt_n + 1):
        if n % i == 0:
            total += i
            other = n // i
            if other != i:
                total += other
    return total

def is_abundant(n):
    return sum_proper_divisors(n) > n

def find_non_abundant_sums(limit):
    abundant_numbers = [i for i in range(12, limit) if is_abundant(i)]
    abundant_sums = set()
    for i in range(len(abundant_numbers)):
        for j in range(i, len(abundant_numbers)):
            sum_ab = abundant_numbers[i] + abundant_numbers[j]
            if sum_ab < limit:
                abundant_sums.add(sum_ab)
            else:
                break

    non_abundant_sums = sum(i for i in range(1, limit) if i not in abundant_sums)
    return non_abundant_sums

print(find_non_abundant_sums(28123))


