def find_fibonacci_index_with_digits(digits):
    fib_prev, fib_curr = 1, 1
    index = 2

    while len(str(fib_curr)) < digits:
        fib_prev, fib_curr = fib_curr, fib_prev + fib_curr
        index += 1

    return index

digits = 1000
print(find_fibonacci_index_with_digits(digits))


+++++ cot_reasoning/26_reciprocal_cycles/reciprocal_cycles.py
def find_reciprocal_cycle_length(d):
    remainders = {}
    remainder = 1 % d
    position = 0

    while remainder != 0 and remainder not in remainders:
        remainders[remainder] = position
        remainder = (remainder * 10) % d
        position += 1

    if remainder == 0:
        return 0
    else:
        return position - remainders[remainder]

def find_longest_reciprocal_cycle(limit):
    max_length = 0
    number = 0

    for d in range(2, limit):
        cycle_length = find_reciprocal_cycle_length(d)
        if cycle_length > max_length:
            max_length = cycle_length
            number = d

    return number

limit = 1000
print(find_longest_reciprocal_cycle(limit))


