import math

def is_prime(n):
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(math.sqrt(n)) + 1, 2):
        if n % i == 0:
            return False
    return True

def count_primes_for_quadratic(a, b):
    n = 0
    while True:
        value = n * n + a * n + b
        if not is_prime(value):
            break
        n += 1
    return n

def find_quadratic_with_most_primes(limit):
    max_primes = 0
    best_a, best_b = 0, 0

    for a in range(-limit + 1, limit):
        for b in range(-limit, limit + 1):
