from fractions import Fraction

def find_digit_cancelling_fractions():
    fractions = []

    for numerator in range(10, 100):
        for denominator in range(numerator + 1, 100):
            num_str, den_str = str(numerator), str(denominator)
            common_digits = set(num_str) & set(den_str)

            if len(common_digits) == 1 and '0' not in common_digits:
                common_digit = common_digits.pop()
                new_num = int(num_str.replace(common_digit, '', 1))
                new_den = int(den_str.replace(common_digit, '', 1))

                if new_den != 0 and Fraction(numerator, denominator) == Fraction(new_num, new_den):
                    fractions.append(Fraction(numerator, denominator))

    return fractions

