            for digit in range(10):
                family = []
                for replacement in range(10):
                    n = replace_digits(int('1' + '0' * (num_digits - 1)), positions, replacement)
                    if is_prime(n) and len(str(n)) == num_digits:
                        family.append(n)
                if len(family) == size:
                    return min(family)
    return None

