import itertools
import math

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            return False
    return True

def are_concatenated_primes(a, b):
    return is_prime(int(str(a) + str(b))) and is_prime(int(str(b) + str(a)))

def find_minimal_prime_pair_set():
    primes = [i for i in range(3, 10000) if is_prime(i)]
    prime_sets = {}

    for a, b in itertools.combinations(primes, 2):
        if are_concatenated_primes(a, b):
            prime_sets.setdefault(a, set()).add(b)
            prime_sets.setdefault(b, set()).add(a)

    for a in prime_sets:
        for b in prime_sets[a]:
            common = prime_sets[a] & prime_sets[b]
            for c in common:
                common2 = common & prime_sets[c]
                for d in common2:
                    common3 = common2 & prime_sets[d]
                    for e in common3:
                        return a + b + c + d + e
    return None

