import math

def continued_fraction_period(n):
    m, d, a = 0, 1, int(math.sqrt(n))
    if a * a == n:
        return 0
    a0 = a
    period = 0
    while a != 2 * a0:
        m = d * a - m
        d = (n - m * m) // d
        a = (a0 + m) // d
        period += 1
    return period

def count_odd_periods(limit):
    return sum(1 for n in range(2, limit + 1) if continued_fraction_period(n) % 2 == 1)

