def sum_digits(n):
    return sum(int(digit) for digit in str(n))

def convergent_of_e(n):
    if n == 1:
        return 2
    sequence = [2]
    k = 1
    while len(sequence) < n:
        sequence.extend([1, 2 * k, 1])
        k += 1
    sequence = sequence[:n]

    numerator = 1
    denominator = sequence[-1]
    for num in reversed(sequence[:-1]):
        numerator, denominator = denominator, num * denominator + numerator
    numerator += 2 * denominator

    return sum_digits(numerator)

