import math

def minimal_x(d):
    m, d_val, a = 0, 1, int(math.sqrt(d))
    if a * a == d:
        return 0
    a0 = a
    num1, num = 1, a
    den1, den = 0, 1
    while num * num - d * den * den != 1:
        m = d_val * a - m
        d_val = (d - m * m) // d_val
        a = (a0 + m) // d_val
        num1, num = num, a * num + num1
        den1, den = den, a * den + den1
    return num

def find_maximal_minimal_x(limit):
    max_x = 0
    best_d = 0
    for d in range(2, limit + 1):
        x = minimal_x(d)
        if x > max_x:
            max_x = x
            best_d = d
    return best_d

