def largest_product_in_grid(grid, length):
    max_product = 0
    rows, cols = len(grid), len(grid[0])

    for i in range(rows):
        for j in range(cols - length + 1):
            product = 1
            for k in range(length):
                product *= grid[i][j + k]
            max_product = max(max_product, product)

    for i in range(rows - length + 1):
        for j in range(cols):
            product = 1
            for k in range(length):
                product *= grid[i + k][j]
            max_product = max(max_product, product)

    for i in range(rows - length + 1):
        for j in range(cols - length + 1):
            product = 1
            for k in range(length):
                product *= grid[i + k][j + k]
            max_product = max(max_product, product)

    for i in range(rows - length + 1):
        for j in range(length - 1, cols):
            product = 1
            for k in range(length):
                product *= grid[i + k][j - k]
            max_product = max(max_product, product)

    return max_product

