import math

def euler_totient(n):
    result = n
    p = 2
    while p * p <= n:
        if n % p == 0:
            while n % p == 0:
                n = n // p
            result -= result // p
        p += 1
    if n > 1:
        result -= result // n
    return result

def is_permutation(a, b):
    return sorted(str(a)) == sorted(str(b))

def find_minimal_totient_ratio(limit):
    min_ratio = float('inf')
    best_n = 0
    for n in range(2, limit):
        phi = euler_totient(n)
        if is_permutation(n, phi):
            ratio = n / phi
            if ratio < min_ratio:
                min_ratio = ratio
                best_n = n
    return best_n

