def find_fraction_left_of_target(target, limit):
    max_fraction = 0
    for d in range(1, limit + 1):
        n = int(d * target) - 1
        while n / d >= target:
            n -= 1
        if n / d > max_fraction:
            max_fraction = n / d
    return Fraction(max_fraction).limit_denominator()

