import math

def count_singular_integer_right_triangles(limit):
    triangles = [0] * (limit + 1)
    for m in range(2, int(math.sqrt(limit)) + 1):
        for n in range(1, m):
            if (m - n) % 2 == 1 and math.gcd(m, n) == 1:
                a = m * m - n * n
                b = 2 * m * n
                c = m * m + n * n
                perimeter = a + b + c
                for k in range(1, limit // perimeter + 1):
                    triangles[k * perimeter] += 1
    return sum(1 for count in triangles if count == 1)

