import math

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            return False
    return True

def count_prime_summations(n):
    primes = [i for i in range(2, n) if is_prime(i)]
    ways = [0] * (n + 1)
    ways[0] = 1
    for prime in primes:
        for j in range(prime, n + 1):
            ways[j] += ways[j - prime]
    return ways[n]

