def count_partitions(limit):
    partitions = [1]
    for n in range(1, limit + 1):
        partitions.append(0)
        k = 1
        while True:
            gk = k * (3 * k - 1) // 2
            if gk > n:
                break
            partitions[n] += (-1) ** (k + 1) * partitions[n - gk]
            gk = k * (3 * k + 1) // 2
            if gk > n:
                break
            partitions[n] += (-1) ** (k + 1) * partitions[n - gk]
            k += 1
        if partitions[n] % 1000000 == 0:
            return n
    return None

