from collections import defaultdict

def find_shortest_passcode(logs):
    graph = defaultdict(set)
    in_degree = defaultdict(int)
    nodes = set()

    for log in logs:
        for i in range(len(log) - 1):
            u, v = log[i], log[i + 1]
            if v not in graph[u]:
                graph[u].add(v)
                in_degree[v] += 1
            nodes.add(u)
            nodes.add(v)

    queue = [node for node in nodes if in_degree[node] == 0]
    passcode = []

    while queue:
        if len(queue) > 1:
            return None
        u = queue.pop(0)
        passcode.append(u)
        for v in graph[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    if len(passcode) != len(nodes):
        return None
    return ''.join(passcode)

with open('keylog.txt', 'r') as file:
    logs = [line.strip() for line in file]

