def minimal_path_sum(matrix):
    n = len(matrix)
    for i in range(n):
        for j in range(1, n):
            matrix[i][j] += matrix[i][j - 1]

    for j in range(1, n):
        for i in range(n):
            min_val = matrix[i][j]
            for k in range(n):
                if i == k:
                    continue
                if i < k:
                    current_sum = sum(matrix[m][j - 1] for m in range(i, k + 1)) + matrix[k][j]
                else:
                    current_sum = sum(matrix[m][j - 1] for m in range(k, i + 1)) + matrix[k][j]
                min_val = min(min_val, current_sum)
            matrix[i][j] = min_val

    return min(matrix[i][n - 1] for i in range(n))

