import heapq

def minimal_path_sum(matrix):
    n = len(matrix)
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
    heap = [(matrix[0][0], 0, 0)]
    visited = set()

    while heap:
        current_sum, i, j = heapq.heappop(heap)
        if (i, j) in visited:
            continue
        visited.add((i, j))
        if i == n - 1 and j == n - 1:
            return current_sum
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < n and 0 <= nj < n:
                heapq.heappush(heap, (current_sum + matrix[ni][nj], ni, nj))

    return -1

with open('matrix.txt', 'r') as file:
    matrix = [list(map(int, line.split(','))) for line in file]

